from pathlib import Path
for fn in ['model.py','train.py','predict.py']:
    p=Path(fn)
    txt=p.read_text()
    print(f'### {fn} bytes={len(txt)} lines={txt.count(chr(10))+1}')
    lines=txt.splitlines()
    if fn=='model.py':
        ranges=[(1,220)]
    elif fn=='train.py':
        ranges=[(1,105),(145,180)]
    else:
        ranges=[(1,80)]
    for a,b in ranges:
        print(f'-- {fn}:{a}-{b}')
        for i in range(a-1,min(b,len(lines))):
            print(f'{i+1:03d}: {lines[i][:140]}')
